import { constrainDomain, constrainRange } from './selection-to-domain';

/**
 *
 * @param axisInfo
 * @param type
 * @param transform
 * @return {{domain: [number, number]}|{range: number[]}}
 */
export function updateScaleByTransform(axisInfo, type, transform, baseRange) {
    var { scale, baseScale, zoomScale, baseZoomScale } = axisInfo,
        domain,
        range,
        constrain = transform.k > 1;

    type = type.toUpperCase();

    if (scale.bandwidth) {
        let originalRange = baseRange || baseScale.range();

        range = originalRange.map(d => transform[`apply${type}`](d));
        if (constrain) {
            range = constrainRange(range, originalRange);
        }
        // fix axis rotated
        scale.range(range);
    } else {
        domain = transform[`rescale${type}`](baseScale).domain();

        if (constrain) {
            // constrain
            domain = constrainDomain(domain, baseScale.originalDomain || scale.originalDomain, scale.outerPadding);
        }
        scale.domain(domain);
    }

    // for zoom scale if available
    if (zoomScale) {
        let zoomDomain = transform[`rescale${type}`](baseZoomScale).domain();
        zoomScale.domain((axisInfo.zoomDomain = zoomDomain));
    }

    return { domain, range };
}
